DROP TRIGGER IF EXISTS `after_evaluation_detail_insert`;
DELIMITER $$
CREATE TRIGGER `after_evaluation_detail_insert` AFTER INSERT ON `evaluation_details` FOR EACH ROW BEGIN
    DECLARE v_employee_id INT;
    
    SELECT employee_id INTO v_employee_id
    FROM evaluations
    WHERE id = NEW.evaluation_id;
    
    -- Only mark as 'completed' if the evaluator actually entered a score > 0
    IF NEW.score IS NOT NULL AND NEW.score > 0 THEN
        ON DUPLICATE KEY UPDATE 
            status = 'completed',
            updated_at = CURRENT_TIMESTAMP;
    END IF;
END
$$
DELIMITER ;
DROP TRIGGER IF EXISTS `after_evaluation_detail_update_score`;
DELIMITER $$
CREATE TRIGGER `after_evaluation_detail_update_score` AFTER UPDATE ON `evaluation_details` FOR EACH ROW BEGIN
    DECLARE total_weighted_score DECIMAL(10,2);
    DECLARE total_weightage DECIMAL(10,2);
    DECLARE v_matrix_id INT;
    
    -- Get the matrix_id for this evaluation
    SELECT cta.matrix_id INTO v_matrix_id
    FROM evaluations ev
    LEFT JOIN cycle_team_assignments cta ON ev.cycle_team_assignment_id = cta.id
    WHERE ev.id = NEW.evaluation_id;
    
    -- Calculate total weighted score for this evaluation
    SELECT 
        SUM(ed.score * pm.weightage / 100),
        SUM(pm.weightage)
    INTO total_weighted_score, total_weightage
    FROM evaluation_details ed
    INNER JOIN parameter_matrices pm ON ed.parameter_id = pm.parameter_id
        AND pm.matrix_id = v_matrix_id
    WHERE ed.evaluation_id = NEW.evaluation_id
    AND ed.score IS NOT NULL;
    
    -- Update the evaluation's overall score and weighted score
    UPDATE evaluations
    SET 
        overall_score = ROUND(total_weighted_score, 2),
        weighted_score = ROUND(total_weighted_score, 2),
        updated_at = CURRENT_TIMESTAMP
    WHERE id = NEW.evaluation_id;
END
$$
DELIMITER ;
DROP TRIGGER IF EXISTS `before_evaluation_detail_insert`;
DELIMITER $$
CREATE TRIGGER `before_evaluation_detail_insert` BEFORE INSERT ON `evaluation_details` FOR EACH ROW BEGIN
    -- Auto-calculate score from rating (rating/5 * 100)
    IF NEW.rating IS NOT NULL THEN
        SET NEW.score = (NEW.rating / 5.0) * 100;
    END IF;
END
$$
DELIMITER ;
DROP TRIGGER IF EXISTS `before_evaluation_detail_update`;
DELIMITER $$
CREATE TRIGGER `before_evaluation_detail_update` BEFORE UPDATE ON `evaluation_details` FOR EACH ROW BEGIN
    -- Auto-calculate score from rating (rating/5 * 100)
    IF NEW.rating IS NOT NULL THEN
